import React from "react";

export default function Modal({ aluno }) {
  /*
    {aluno.nome}
    {aluno.turma}
    {aluno.pontuacao} 
    */
  return (
    <div className="bg-branco h-28 rounded-full flex">
      <div className="bg-red-900 w-28 h-28 rounded-full inline-flex">
        <h1 className="text-white text-7xl self-center mx-auto">1°</h1>
      </div>

      <div>
        <h1>Nome do Aluno</h1>
      </div>
    </div>
  );
}
